# Secret key for HMAC integrity verification
HMAC_SECRET = os.environ.get('HMAC_SECRET', secrets.token_hex(32))

def generate_hmac(data):
    """Generate HMAC for data integrity"""
    message = json.dumps(data, sort_keys=True).encode()
    return hmac.new(HMAC_SECRET.encode(), message, hashlib.sha256).hexdigest()

def verify_hmac(data, provided_hmac):
    """Verify HMAC for data integrity"""
    expected_hmac = generate_hmac(data)
    return hmac.compare_digest(expected_hmac, provided_hmac)

def sanitize_label(label):
    """Sanitize and validate label input"""
    if not isinstance(label, (str, int)):
        raise ValueError("Invalid label type")
    label_str = str(label).strip()
    if len(label_str) > 100:
        raise ValueError("Label too long")
    return label_str

def sanitize_annotator_id(annotator_id):
    """Sanitize and validate annotator ID"""
    if not isinstance(annotator_id, str):
        raise ValueError("Invalid annotator ID type")
    annotator_id = annotator_id.strip()
    if len(annotator_id) > 100 or len(annotator_id) == 0:
        raise ValueError("Invalid annotator ID length")
    return annotator_id

def sanitize_image_id(image_id):
    """Sanitize and validate image ID"""
    if not isinstance(image_id, str):
        raise ValueError("Invalid image ID type")
    image_id = image_id.strip()
    if len(image_id) > 100 or len(image_id) == 0:
        raise ValueError("Invalid image ID length")
    return image_id

