@app.route('/aggregate_labels/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    """Aggregate labels using majority voting with integrity verification"""
    try:
        image_id = sanitize_image_id(image_id)
        
        if image_id not in labels_storage:
            return jsonify({'error': 'No labels found for this image'}), 404
        
        # Verify integrity of all labels before aggregation
        verified_labels = []
        for label_record in labels_storage[image_id]:
            if verify_hmac(label_record['data'], label_record['hmac']):
                verified_labels.append(label_record['data']['label'])
            else:
                # Log integrity violation but continue with verified labels
                app.logger.warning(f"Label integrity violation detected for image {image_id}")
        
        if not verified_labels:
            return jsonify({'error': 'No verified labels found'}), 404
        
        # Majority voting on verified labels only
        label_counts = Counter(verified_labels)
        majority_label = label_counts.most_common(1)[0][0]
        confidence = label_counts[majority_label] / len(verified_labels)
        
        aggregated_data = {
            'image_id': image_id,
            'majority_label': majority_label,
            'confidence': confidence,
            'total_labels': len(verified_labels),
            'label_distribution': dict(label_counts)
        }
        
        # Store aggregated result with integrity protection
        aggregated_hmac = generate_hmac(aggregated_data)
        
        images_storage[image_id] = {
            'data': aggregated_data,
            'hmac': aggregated_hmac
        }
        
        return jsonify(aggregated_data), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

